export type TechCardMediaFull = {
  media: MediaFull | undefined;
  kind: TechCardMediaKind | undefined;
  caption: string | undefined;
};

// TechCardCallout is a numbered detail note pointing at the technical sketch.
export type TechCardCallout = {
  number: number | undefined;
  part: string | undefined;
  description: string | undefined;
  dimensions: string | undefined;
  mediaId: number | undefined;
  posX: googletype_Decimal | undefined;
  posY: googletype_Decimal | undefined;
};

// TechCardRevision is one entry in the spec-document changelog (what changed in
// which section, by whom). This is NOT fit history — fitting verdicts and
// measurements live in the separate fitting feature.
export type TechCardRevision = {
  version: string | undefined;
  revisionDate: wellKnownTimestamp | undefined;
  author: string | undefined;
  section: string | undefined;
  changeNote: string | undefined;
  action: string | undefined;
  createdAt: wellKnownTimestamp | undefined;
};

// TechCardRoleAssignment is one "this admin account is <role> of this card" record (Q5), multi per
// role. Managed via the AssignTechCardRole / RemoveTechCardRoleAssignment / ListTechCardRoleAssignments
// RPCs, NOT through the tech-card full-replace. admin_username is resolved on read (never written).
export type TechCardRoleAssignment = {
  id: number | undefined;
  techCardId: number | undefined;
  role: TechCardRole | undefined;
  adminId: number | undefined;
  adminUsername: string | undefined;
  assignedBy: string | undefined;
  assignedAt: wellKnownTimestamp | undefined;
};

// ColorwayDevelopmentInsert carries the PLM / lab-dip development fields that moved onto the colourway
// (product) in the R1 merge: ex tech_card_colorway.code/name/hex/comment become dev_code/name/dev_hex/
// comment. Lives in techcard.proto to reach TechCardLabDipStatus and the usage recipe without a circular
// import (product.proto cannot import techcard.proto). NOTE: `usages` (the material recipe) is keyed by
// an explicit colorway_id = product.id (R1/§14.3); the positional colorway_index model is gone.
export type ColorwayDevelopmentInsert = {
  devCode: string | undefined;
  name: string | undefined;
  labDipStatus: TechCardLabDipStatus | undefined;
  comment: string | undefined;
  pantone: string | undefined;
  pantoneSystem: string | undefined;
  devHex: string | undefined;
  swatchMediaId: number | undefined;
  labDipRound: number | undefined;
  labDipSubmittedAt: wellKnownTimestamp | undefined;
  labDipDecidedAt: wellKnownTimestamp | undefined;
  labDipDecidedBy: string | undefined;
  labDipRejectReason: string | undefined;
  usages: TechCardColorwayUsage[] | undefined;
  displayOrder: number | undefined;
};

// TechCardColorwayUsage is one material use inside a colourway: which catalog article
// (bom_item_index) goes on which garment part (placement), the colour it takes HERE, and
// how much is consumed (per-garment and/or per-size). The BOM is a pure article catalog;
// per-colourway divergence lives here.
export type TechCardColorwayUsage = {
  // explicit presence: index 0 is a real BOM line, distinct from "unset"
  // (mirrors TechCardOperation.bom_item_index).
  bomItemIndex?: number;
  placement: string | undefined;
  // matched (trim+lower) against TechCardOperation.placement
  color: string | undefined;
  // independent of the colourway swatch pantone (ColorwayDevelopmentInsert.pantone)
  pantone: string | undefined;
  consumption: googletype_Decimal | undefined;
  quantity: googletype_Decimal | undefined;
  sizeConsumptions: TechCardBomSizeConsumption[] | undefined;
  lineTotal: googletype_Decimal | undefined;
  sizeRunTotal: googletype_Decimal | undefined;
  // explicit presence: 0-based index into TechCardInsert.pieces saying which cut-piece this
  // consumption norm is about; unset = whole garment (informational, NF-05).
  pieceIndex?: number;
  // bom_line_key references the owning style's BOM line by its stable line_key (S2/S3) — the durable
  // reference the recipe write-path resolves to a real bom_item_id. Preferred over bom_item_index
  // (which stays for the transition / legacy read). bom_item_id is the resolved FK on read.
  bomLineKey: string | undefined;
  bomItemId: number | undefined;
  // piece_line_key references the cut-piece this norm is about by its stable TechCardPiece.line_key
  // (WS4). The recipe write-path resolves it to the real piece_id FK (usage.piece_id RESTRICT).
  // Preferred over the positional piece_index (kept for the transition). piece_id is the resolved FK.
  pieceLineKey: string | undefined;
  pieceId: number | undefined;
};

// TechCardBomSizeConsumption is the per-size consumption (норма расхода) of one BOM
// material — different sizes consume different amounts of fabric.
export type TechCardBomSizeConsumption = {
  sizeId: number | undefined;
  consumption: googletype_Decimal | undefined;
};

export type ColorwayDevelopment = {
  development: ColorwayDevelopmentInsert | undefined;
  dictionaryColor: Color | undefined;
};

// StyleSizeChart is the style-owned size chart (R5). Written full-replace under the shared
// tech_card.lock_version; there is no separate chart version.
export type StyleSizeChartCell = {
  sizeId: number | undefined;
  measurementNameId: number | undefined;
  value: googletype_Decimal | undefined;
};

export type StyleSizeChart = {
  styleId: number | undefined;
  lockVersion: number | undefined;
  cells: StyleSizeChartCell[] | undefined;
};

// AdminColorwayRef is a derived, output-only reference to a colourway from its style (R1: GetStyle may
// return its colourways, but they are not writable through the style).
export type AdminColorwayRef = {
  colorwayId: number | undefined;
  baseSku: string | undefined;
  colorCode: string | undefined;
  status: ColorwayLifecycleStatus | undefined;
  // usages is this colourway's material recipe (H1 fix, WS3/S2-S3): the constructor view of a
  // style now shows each colourway's recipe alongside its identity, instead of the recipe being
  // write-only (UpdateColorwayRecipe persisted usages that no read path ever surfaced). Money
  // fields (line_total/size_run_total) are stripped for an account without costing:read, same as
  // the rest of the tech-card read (stripTechCardCosting).
  usages: TechCardColorwayUsage[] | undefined;
  // Lab-dip lifecycle mirrored from the colourway's development submessage (ColorwayDevelopmentInsert),
  // so the tech-card colourways tab can READ the current lab-dip state inline instead of a second
  // GetColorwayByID round-trip. These are written through the Colorway write path (UpdateColorway's
  // development.*), never through the style; here they are output-only.
  labDipStatus: TechCardLabDipStatus | undefined;
  labDipRound: number | undefined;
  labDipSubmittedAt: wellKnownTimestamp | undefined;
  labDipDecidedAt: wellKnownTimestamp | undefined;
  labDipDecidedBy: string | undefined;
  labDipRejectReason: string | undefined;
  // lock_version is the colourway's optimistic-lock token — its style's shared tech_card.lock_version
  // (R2/R4). Echo it into UpdateColorwayRequest.expected_colorway_version; a stale value is rejected
  // (ABORTED). Surfaced on the ref so a per-colourway lab-dip edit is optimistically locked straight
  // from here, without the caller reaching up to the tech-card's top-level lock_version.
  lockVersion: number | undefined;
};

// TechCardDetail is one aspect of the construction description (Sheet «Титул», lower block)
// with optional reference images. key is freeform (silhouette/collar/fastening/pockets/
// sleeve_cuff/topstitching/extra_details … or a custom aspect).
export type TechCardDetail = {
  key: string | undefined;
  text: string | undefined;
  mediaIds: number[] | undefined;
};

// TechCardBomItem is one bill-of-materials line — a catalog article (Sheet «Спецификация»).
// The per-colourway colour, placement and consumption live on TechCardColorwayUsage; the
// BOM line is now a pure material-article catalog entry.
export type TechCardBomItem = {
  section: TechCardBomSection | undefined;
  name: string | undefined;
  supplier: string | undefined;
  supplierRef: string | undefined;
  color: string | undefined;
  composition: string | undefined;
  spec: string | undefined;
  unit: string | undefined;
  unitPrice: googletype_Decimal | undefined;
  currency: string | undefined;
  comment: string | undefined;
  // fabric data for the cutter / marker (Phase 3.5c)
  fabricWidth: googletype_Decimal | undefined;
  fabricWeightGsm: googletype_Decimal | undefined;
  fabricDirection: TechCardFabricDirection | undefined;
  wastagePercent: googletype_Decimal | undefined;
  // material_id optionally links this line to a catalog Material (task 10). The line keeps its
  // own snapshot fields regardless; 0 means unlinked (free-text / legacy).
  materialId: number | undefined;
  // id is the stable server-assigned PK (read-only). line_key is the client-generated ULID assigned
  // when the line is first created in the UI, round-tripped on every save so the server keyed-
  // reconciles by it (S2/S3) and keeps id stable — which is what lets operations/pieces/recipes hold
  // a real FK instead of a fragile positional index.
  id: number | undefined;
  lineKey: string | undefined;
  // material_snapshot is a read-only JSON snapshot of the linked material's descriptive fields at
  // save time (S23), so the document is self-contained.
  materialSnapshot: string | undefined;
};

// MaterialFabricAttrs are the typed attributes of a fabric-class material (material_fabric_attr).
export type MaterialFabricAttrs = {
  widthCm: googletype_Decimal | undefined;
  weightGsm: googletype_Decimal | undefined;
  fabricDirection: string | undefined;
  shrinkagePct: googletype_Decimal | undefined;
  rollLengthM: googletype_Decimal | undefined;
};

// MaterialHardwareAttrs are the typed attributes of a hardware-class material (material_hardware_attr).
export type MaterialHardwareAttrs = {
  diameterMm: googletype_Decimal | undefined;
  dimensions: string | undefined;
  finish: string | undefined;
  baseMaterial: string | undefined;
  weightG: googletype_Decimal | undefined;
};

// MaterialThreadAttrs are the typed attributes of a thread-class material (material_thread_attr).
// Fibre composition is not here — it lives in the structural material_composition (S17).
export type MaterialThreadAttrs = {
  ticketTex: string | undefined;
  lengthPerConeM: googletype_Decimal | undefined;
  needleReco: string | undefined;
};

// MaterialPackagingAttrs are the typed attributes of a packaging-class material (material_packaging_attr).
export type MaterialPackagingAttrs = {
  substrate: string | undefined;
  dimensions: string | undefined;
  gsm: googletype_Decimal | undefined;
  printMethod: string | undefined;
};

export type Material = {
  id: number | undefined;
  name: string | undefined;
  section: TechCardBomSection | undefined;
  supplier: string | undefined;
  supplierRef: string | undefined;
  composition: string | undefined;
  spec: string | undefined;
  unit: string | undefined;
  fabricWidth: googletype_Decimal | undefined;
  fabricWeightGsm: googletype_Decimal | undefined;
  archived: boolean | undefined;
  // latest_price is the current (latest-effective) price, if any (read-only; set via
  // AddMaterialPrice). Absent when the material has no price history yet.
  latestPrice: MaterialPrice | undefined;
  // Warehouse catalog fields (new-flow NF-02).
  code: string | undefined;
  color: string | undefined;
  pantone: string | undefined;
  minStock: googletype_Decimal | undefined;
  notes: string | undefined;
  // lock_version is the optimistic-lock counter (S25, read-only). Echo it back in
  // UpdateMaterialRequest.expected_lock_version; a stale value is rejected (Aborted).
  lockVersion: number | undefined;
  // CTI typing (S15): material_class selects which typed attribute set applies. Exactly one of the
  // `attributes` oneof is populated for the four typed classes; other_attrs (a JSON object) is the
  // escape-hatch used only when material_class = MATERIAL_CLASS_OTHER.
  materialClass: MaterialClass | undefined;
  fabricAttrs?: MaterialFabricAttrs;
  hardwareAttrs?: MaterialHardwareAttrs;
  threadAttrs?: MaterialThreadAttrs;
  packagingAttrs?: MaterialPackagingAttrs;
  otherAttrs: string | undefined;
  // Structural fibre composition (S17): fiber_code + percent, summing to 100 when present. Replaces
  // the free-text `composition` string (which stays legacy plain text). On write, only fiber_code +
  // percent are read (name is resolved server-side from the fibre dictionary). Empty = unset. A
  // shell-fabric material's composition is what a style's derived composition_entries is built from.
  compositionEntries: CompositionEntry[] | undefined;
  // Catalog image (#39): image_id is the write-side media reference (FK media(id); 0 = unset); image
  // is the resolved MediaFull on read (null when unset). Mirrors Model.thumbnail_id / Model.thumbnail.
  imageId: number | undefined;
  image: MediaFull | undefined;
  // purpose (#40) marks whether the material is used for samples, production, or both. Defaults to
  // BOTH on write when UNKNOWN, so the admin can mark and filter materials.
  purpose: MaterialPurpose | undefined;
};

// MaterialPrice is one point in a material's append-only price history. Prices are in the
// purchase currency (fold to base via costing FX rates).
export type MaterialPrice = {
  materialId: number | undefined;
  price: googletype_Decimal | undefined;
  currency: string | undefined;
  validFrom: wellKnownTimestamp | undefined;
  source: string | undefined;
  note: string | undefined;
};

// TechCardReleaseMeta is the header of an immutable release snapshot (task 11) without the
// JSON blob — the frozen spec + planned unit cost captured when a card entered `released`.
// The full snapshot (a proto-JSON contract TechCard) is fetched via GetTechCardRelease.
export type TechCardReleaseMeta = {
  id: number | undefined;
  techCardId: number | undefined;
  version: string | undefined;
  releaseNumber: number | undefined;
  releasedBy: string | undefined;
  unitCost: googletype_Decimal | undefined;
  currency: string | undefined;
  createdAt: wellKnownTimestamp | undefined;
};

// TechCardDevExpenseInsert is the writable payload for one development (R&D) cost row (task 14):
// a one-off "spent Amount on Kind" record. amount_base is computed server-side (via costing FX);
// clients do not send it.
export type TechCardDevExpenseInsert = {
  techCardId: number | undefined;
  kind: string | undefined;
  description: string | undefined;
  amount: googletype_Decimal | undefined;
  currency: string | undefined;
  fittingId: number | undefined;
  incurredAt: wellKnownTimestamp | undefined;
  sampleId: number | undefined;
};

// TechCardDevExpense is one stored development-cost journal row. amount_base folds amount to base
// (EUR) via costing FX (unset when the currency has no rate).
export type TechCardDevExpense = {
  id: number | undefined;
  techCardId: number | undefined;
  kind: string | undefined;
  description: string | undefined;
  amount: googletype_Decimal | undefined;
  currency: string | undefined;
  amountBase: googletype_Decimal | undefined;
  fittingId: number | undefined;
  incurredAt: wellKnownTimestamp | undefined;
  createdAt: wellKnownTimestamp | undefined;
  sampleId: number | undefined;
};

// TechCardDevCostByKind is the base-currency development spend for one kind.
export type TechCardDevCostByKind = {
  kind: string | undefined;
  amountBase: googletype_Decimal | undefined;
};

// TechCardDevCostByRound is a style's development spend attributed to one fitting round (Q8 — the
// attribution S20 asked to fix). round_number 0 collects expenses tied to no fitting round.
export type TechCardDevCostByRound = {
  roundNumber: number | undefined;
  amountBase: googletype_Decimal | undefined;
  expenseCount: number | undefined;
};

// TechCardDevCostSummary is the computed roll-up of a style's development spend (output-only).
export type TechCardDevCostSummary = {
  totalBase: googletype_Decimal | undefined;
  hasUnconverted: boolean | undefined;
  byKind: TechCardDevCostByKind[] | undefined;
  // Amortized informational figure: production unit_cost + total_base / Σ order_qty — how much
  // development adds to each unit at the current size run. Unset when order_qty is 0 or the
  // production unit cost is unavailable. NOT part of cost_price (development is a period cost).
  unitCostWithDev: googletype_Decimal | undefined;
  orderQty: number | undefined;
  // Q8 rollup (read projection, built alongside — never seeded into cost_price):
  byRound: TechCardDevCostByRound[] | undefined;
  roundsToApproval: number | undefined;
  firstExpenseAt: wellKnownTimestamp | undefined;
  approvedAt: wellKnownTimestamp | undefined;
  daysToApproval: number | undefined;
};

// TechCardSizeQuantity is the production order quantity for a size (size run).
export type TechCardSizeQuantity = {
  sizeId: number | undefined;
  orderQty: number | undefined;
};

// TechCardSizePattern is a downloadable PDF выкройка (cut pattern) for one size of a
// tech card — the FINAL pattern for that size. A size can carry many patterns (pieces
// split across sheets). The PDF is uploaded via Admin.UploadPattern, which returns the
// url stored here; the binary lives in object storage, not the media library.
export type TechCardSizePattern = {
  sizeId: number | undefined;
  url: string | undefined;
  filename: string | undefined;
  sizeBytes: number | undefined;
};

// TechCardConstruction holds general workmanship parameters (Sheet «Обработка»).
export type TechCardConstruction = {
  mainStitchType: string | undefined;
  stitchDensity: string | undefined;
  overlockThreads: string | undefined;
  seamAllowances: string | undefined;
  hemFinish: string | undefined;
  pressing: string | undefined;
  machineClass: string | undefined;
  notes: string | undefined;
};

// TechCardOperation is one per-node sewing operation (Sheet «Обработка»).
export type TechCardOperation = {
  node: string | undefined;
  description: string | undefined;
  seamType: string | undefined;
  stitchesPerCm: googletype_Decimal | undefined;
  topstitchWidth: string | undefined;
  thread: string | undefined;
  note: string | undefined;
  operationNumber: number | undefined;
  machine: string | undefined;
  seamAllowance: string | undefined;
  needle: string | undefined;
  timeNorm: googletype_Decimal | undefined;
  attachment: string | undefined;
  operationType: TechCardOperationType | undefined;
  // 0-based index into TechCardInsert.bom_items of the material this operation
  // applies (thread / binding (бейка) / interlining / zipper) when it is NOT resolved
  // through a part. Uses proto3 explicit presence so index 0 (the first BOM line) is
  // distinguishable from "no material": unset = no reference. When set, it wins; the
  // colour resolves via the selected colourway's usage with the same bom_item_index.
  bomItemIndex?: number;
  calloutNumber: number | undefined;
  zone: TechCardConstructionZone | undefined;
  placement: string | undefined;
  // via the selected colourway's usages (match trim+lower; bom_item_index wins if set)
  // bom_line_key references the BOM line by its stable line_key (WS3 follow-up: take positionality off
  // the wire). Preferred over the positional bom_item_index (kept for the transition). The store
  // resolves it to bom_item_id, the real FK on read.
  bomLineKey: string | undefined;
  bomItemId: number | undefined;
};

// TechCardIssue is a maker-flagged problem ("this seam is impossible") against an
// operation or callout (Sheet «Обработка» / «Тех. эскиз»).
export type TechCardIssue = {
  operationNumber: number | undefined;
  calloutNumber: number | undefined;
  raisedBy: string | undefined;
  severity: TechCardIssueSeverity | undefined;
  status: TechCardIssueStatus | undefined;
  description: string | undefined;
  resolutionNote: string | undefined;
};

// TechCardLabel is one label / tag spec (Sheet «Этикетки и упаковка»).
// TechCardLabel is the garment's label/tag SPEC — one of the three historically-unconnected "label"
// concepts (S21): (a) THIS spec, (b) the shipment label (common/shipment.proto — a shipping document,
// deliberately NOT merged, a different domain), (c) the label MATERIAL as a BOM line
// (tech_card_bom_item, section=label). WS7 unifies (a)↔(c) via bom_item_id below, and classifies the
// auxiliary item via TechCard.aux_subtype. DEPRECATION (destructive → M3, not done here): once
// bom_item_id + aux_subtype are adopted, label_type collapses into aux_subtype and the free-text
// content/placement/attachment/size overlap (also carried structurally by the linked material + the
// assembly bill's print_note/position_note) is dropped in a guarded migration.
export type TechCardLabel = {
  labelType: TechCardLabelType | undefined;
  content: string | undefined;
  placement: string | undefined;
  attachment: string | undefined;
  size: string | undefined;
  note: string | undefined;
  // WS7/§2.8 (S21 unification bridge): FK to the physical label material's BOM line
  // (tech_card_bom_item). 0 = unlinked. Links this free-text label SPEC to the material it prints on.
  bomItemId: number | undefined;
};

// TechCardPackaging holds the packaging spec (Sheet «Этикетки и упаковка»).
export type TechCardPackaging = {
  foldingMethod: string | undefined;
  polybag: string | undefined;
  bagSticker: string | undefined;
  inserts: string | undefined;
  unitsPerBox: number | undefined;
  boxMarking: string | undefined;
  boxDimensions: string | undefined;
  weightNetGrams: number | undefined;
  weightGrossGrams: number | undefined;
  notes: string | undefined;
};

// TechCardCostLine is one currency bucket of the materials rollup.
export type TechCardCostLine = {
  currency: string | undefined;
  amount: googletype_Decimal | undefined;
};

// TechCardColorwayCost is the computed cost of ONE colourway (Sheet «Калькуляция»),
// OUTPUT-ONLY (ignored on write). Materials come from that colourway's usages; the manual
// articles (CMT/hardware/…) are shared across colourways, so unit_cost folds them in. All
// figures are per GARMENT except order_cost (whole run). No FX conversion.
export type TechCardColorwayCost = {
  colorwayId: number | undefined;
  materialsTotal: TechCardCostLine[] | undefined;
  materialsPerUnit: googletype_Decimal | undefined;
  unitCost: googletype_Decimal | undefined;
  orderQty: number | undefined;
  orderCost: googletype_Decimal | undefined;
  hasUnconvertedCurrencies: boolean | undefined;
};

// TechCardCosting holds the manually-entered per-unit cost articles (Sheet «Калькуляция»).
// Everything is in a SINGLE currency. The materials line and the unit/order totals are
// COMPUTED on read (output-only, ignored on write). Model: cost is built per GARMENT, then
// scaled to the whole order by order_qty. There is NO pricing here — markup/wholesale/retail
// were removed; pricing lives on the published product.
export type TechCardCosting = {
  // manual per-unit cost articles (per ONE garment), all in `currency`.
  cmtCost: googletype_Decimal | undefined;
  hardwareCost: googletype_Decimal | undefined;
  packagingCost: googletype_Decimal | undefined;
  logisticsCost: googletype_Decimal | undefined;
  overheadCost: googletype_Decimal | undefined;
  defectPercent: googletype_Decimal | undefined;
  currency: string | undefined;
  notes: string | undefined;
  // OUTPUT-ONLY computed rollup (ignored on write). Root figures are the PRIMARY colourway
  // (colorways index 0); per-colourway figures are in colorway_costs. Materials come from the
  // BOM via each colourway's usages, normalised to a PER-GARMENT figure (a usage graded only
  // per size is divided by order_qty), then taken in the single `currency` — a BOM line in
  // another currency is flagged in has_unconverted_currencies and left out of materials_per_unit
  // (it still appears in materials_total under its own currency, never silently dropped).
  materialsTotal: TechCardCostLine[] | undefined;
  materialsPerUnit: googletype_Decimal | undefined;
  unitCost: googletype_Decimal | undefined;
  orderQty: number | undefined;
  orderCost: googletype_Decimal | undefined;
  hasUnconvertedCurrencies: boolean | undefined;
  totalSam: googletype_Decimal | undefined;
  colorwayCosts: TechCardColorwayCost[] | undefined;
  // OUTPUT-ONLY base-currency rollup. The unit/order cost of the primary colourway folded into
  // the base currency via the manual costing FX rates. Set ONLY when every currency involved
  // has a rate — this is the figure the product-cost seed uses, so a non-base costing can seed
  // cost_price too. Absent when a needed rate is missing (then has_unconverted_currencies).
  unitCostBase: googletype_Decimal | undefined;
  orderCostBase: googletype_Decimal | undefined;
  baseCurrency: string | undefined;
};

// TechCardSignoff records one responsible role's sign-off of a sheet, so the
// header approval_state isn't the only gate (Sheet «Титул» coordination).
export type TechCardSignoff = {
  section: TechCardSignoffSection | undefined;
  state: TechCardSignoffState | undefined;
  signedBy: string | undefined;
  signedAt: wellKnownTimestamp | undefined;
  note: string | undefined;
};

// TechCardPieceColorwayMaterial maps ONE cut-piece to its fabric (and optional fusing) for ONE
// colourway. The colourway is addressed by an explicit colorway_id = product.id (R1/§14.3); the old
// positional colorway_index into TechCardInsert.colorways is gone (colourways are no longer style
// children). The BOM refs remain positional into TechCardInsert.bom_items.
export type TechCardPieceColorwayMaterial = {
  colorwayId: number | undefined;
  bomItemIndex?: number;
  fusingBomItemIndex?: number;
  note: string | undefined;
  // bom_line_key / fusing_bom_line_key reference the fabric / fusing BOM line by its stable line_key
  // (WS3 follow-up: positionality off the wire). Preferred over the positional *_index (kept for the
  // transition). The store resolves them to the real FKs bom_item_id / fusing_bom_item_id (output).
  bomLineKey: string | undefined;
  fusingBomLineKey: string | undefined;
  bomItemId: number | undefined;
  fusingBomItemId: number | undefined;
};

// TechCardPiece is one structural cut-piece of the garment (полочка, спинка, обтачка горловины…):
// how many per garment, whether mirrored/paired, its grainline (долевая) and whether it is fused
// (клеевая). materials picks, per colourway, which BOM fabric it is cut from. Full-replace child.
export type TechCardPiece = {
  name: string | undefined;
  piecesPerGarment: number | undefined;
  // Q6: mirrored means the piece is CUT AS A MIRRORED PAIR (left+right), not a decorative flag. The
  // cut-list (GetStyleCutList) expands a mirrored piece ×2 over pieces_per_garment.
  mirrored: boolean | undefined;
  grainline: string | undefined;
  fused: boolean | undefined;
  calloutNumber?: number;
  note: string | undefined;
  materials: TechCardPieceColorwayMaterial[] | undefined;
  // line_key is the stable client-generated ULID identity of the cut-piece (S8, mirrors BOM's
  // line_key): the store keyed-upserts by it so the piece id stays stable across saves, which is what
  // lets a colourway recipe usage hold a real piece_id FK. Empty on a legacy payload → server mints one.
  lineKey: string | undefined;
  // detached is OUTPUT-ONLY: the store sets it when the piece's callout_number no longer resolves to a
  // callout on the card (its source sketch callout was removed) — the piece survives, visibly
  // detached, instead of being silently dropped (orphan-control, S8).
  detached: boolean | undefined;
};

// SkuSeason is the normalized style-owned season used in every SKU. The pair is atomic: callers
// either omit the whole message (early draft/idea) or provide both a known code and a 2000..2099
// year. Free-text season labels are not part of the contract.
export type SkuSeason = {
  code: SeasonEnum | undefined;
  year: number | undefined;
};

export type TechCardInsert = {
  // identification (Sheet «Титул»)
  // Артикул. Required from the PROTO stage onward; OPTIONAL (empty) while stage == IDEA — an idea
  // is by definition pre-article (NF-03/B-2). Moving a card out of IDEA without a real style
  // number is rejected with InvalidArgument. A hand-typed override must set style_number_source =
  // MANUAL and pass the strict format validator; the global UNIQUE(style_number) index is the
  // authority on collisions (Q1). Use SuggestStyleNumber to get the server proposal.
  styleNumber: string | undefined;
  styleNumberSource: StyleNumberSource | undefined;
  name: string | undefined;
  brand: string | undefined;
  collection: string | undefined;
  categoryId: number | undefined;
  targetGender: GenderEnum | undefined;
  stage: TechCardStage | undefined;
  status: string | undefined;
  approvalState: TechCardApprovalState | undefined;
  // approved_by (36) removed (Q5): approval is the APPROVER role + a server-stamped journal event,
  // not a free-text name. version (10) / revision_date (11) removed (Q1): the card's version is the
  // sequence of named releases (Rev.N) + the auto-journal, not a free-text string. designer (14) /
  // constructor (15) / technologist (16) removed (Q5): roles are admin-account assignments now (see
  // the role-assignment RPCs). All are dropped from tech_card in M3.
  releasedAt: wellKnownTimestamp | undefined;
  measurementUnit: TechCardMeasurementUnit | undefined;
  baseModelId: number | undefined;
  baseSampleSizeId: number | undefined;
  // construction description (lower block of Sheet «Титул») now lives in details[]; the
  // header targets / currency were removed (pricing is on costing, single brand policy).
  notes: string | undefined;
  // children (full-replace on update)
  sizeIds: number[] | undefined;
  // Sketch media split into two INDEPENDENT lists (replaces the single `media = 32`):
  // moodboard_media — mood / inspiration / reference / fabric-swatch photos (design intent)
  // technical_media — flat sketches used in construction (front / back / detail / lining / preview)
  // Construction consumes ONLY technical_media. Each item's `kind` sub-classifies within its
  // list. Both are full-replace on update. A callout pins onto ANY media_id on the card — moodboard
  // OR technical (the backend does not restrict the category), so at the idea stage a callout can pin
  // onto a moodboard/reference image before any technical sketch exists.
  moodboardMedia: TechCardMediaItem[] | undefined;
  technicalMedia: TechCardMediaItem[] | undefined;
  callouts: TechCardCallout[] | undefined;
  // materials (Phase 2): bill of materials (article catalog). Colourways are no longer style
  // children (R1 merge — a colourway is a product); their material recipe lives on the colourway via
  // ColorwayDevelopmentInsert.usages, keyed by an explicit colorway_id = product.id.
  // CONTRACT (nf05-01): downstream references into bom_items are POSITIONAL, by index, and every
  // write is a full replace (bom_items have no stable ids across a save). So when a BOM line is
  // removed or reordered, the client MUST renumber all downstream bom_item_index / fusing_bom_item_index
  // in the SAME payload (operations, pieces). An out-of-range index is rejected; an in-range-but-wrong
  // one is not — the server range-checks but cannot detect a wrong-but-valid index. Pieces address
  // their colourway by explicit colorway_id (not a positional index).
  bomItems: TechCardBomItem[] | undefined;
  // production (Phase 3): construction, operations, labels, packaging, costing.
  construction: TechCardConstruction | undefined;
  operations: TechCardOperation[] | undefined;
  labels: TechCardLabel[] | undefined;
  packaging: TechCardPackaging | undefined;
  costing: TechCardCosting | undefined;
  // hardening (Phase 3.5a)
  approvedAt: wellKnownTimestamp | undefined;
  concept: string | undefined;
  issues: TechCardIssue[] | undefined;
  sizeQuantities: TechCardSizeQuantity[] | undefined;
  signoffs: TechCardSignoff[] | undefined;
  patterns: TechCardSizePattern[] | undefined;
  // construction-description aspects with reference images (replaces the flat strings).
  details: TechCardDetail[] | undefined;
  // structural cut-pieces (детали кроя) + per-colourway fabric mapping (NF-05). Full-replace.
  pieces: TechCardPiece[] | undefined;
  // NF-07 auxiliary items. purpose is "sellable" (default/empty) or "auxiliary"; an auxiliary card
  // produces a packaging material rather than a product, so it may not link products and its run
  // output receipts into output_material_id (required before the first run; 0 = unset).
  purpose: TechCardPurpose | undefined;
  outputMaterialId: number | undefined;
  skuSeason: SkuSeason | undefined;
  // WS7: sub-classifies an auxiliary card (UNKNOWN=unset). Ignored / must be UNKNOWN for a sellable card.
  auxSubtype: TechCardAuxSubtype | undefined;
};

// TechCard is a stored tech card with resolved sketch media.
export type TechCard = {
  id: number | undefined;
  techCard: TechCardInsert | undefined;
  createdAt: wellKnownTimestamp | undefined;
  updatedAt: wellKnownTimestamp | undefined;
  lockVersion: number | undefined;
  // Server-stamped audit usernames (norm §2.11, GetAdminUsername). Read-only: set by the server on
  // create/update, never accepted from the write payload.
  createdBy: string | undefined;
  updatedBy: string | undefined;
  // Responsible-account roles (Q5), read-only here — managed via the role-assignment RPCs, not the
  // tech-card write. Replaces the removed free-text designer/constructor/technologist strings.
  roleAssignments: TechCardRoleAssignment[] | undefined;
  // Server-stamped auto-journal (Q1): who/what/when across the card's significant transitions.
  // Read-only — appended by the server, never client-supplied. Replaces the removed input `revisions`.
  revisions: TechCardRevision[] | undefined;
  // Resolved sketch media (MediaFull), split to mirror the writable lists.
  resolvedMoodboardMedia: TechCardMediaFull[] | undefined;
  resolvedTechnicalMedia: TechCardMediaFull[] | undefined;
  // OUTPUT-ONLY derived colourways of this style (R1/§3.3): a style's colourways are its products.
  // Not writable through the style — created/relinked via the Colorway RPCs.
  colorways: AdminColorwayRef[] | undefined;
  // composition_entries is the style's structured fibre composition (S17/M1 fix), resolved from
  // style_composition; empty when the style has no structural composition data yet. Read-only,
  // admin/constructor view — the storefront's equivalent is StorefrontColorwayDisplay.composition_entries.
  compositionEntries: CompositionEntry[] | undefined;
  // fit / composition (legacy free-text) / care_instructions are style catalogue facts stored on
  // the tech_card row but WRITTEN via UpdateStyle (StylePatch), not the tech-card write — so they are
  // read-only projections here, surfaced for the constructor to display and edit-in-place (the admin
  // saves them through UpdateStyle). composition is always legacy plain text on the wire (M1); the
  // structured fibre breakdown is composition_entries above.
  fit: string | undefined;
  composition: string | undefined;
  careInstructions: string | undefined;
};

// TechCardListItem is a lightweight tech-card header for list views.
export type TechCardListItem = {
  id: number | undefined;
  styleNumber: string | undefined;
  name: string | undefined;
  brand: string | undefined;
  stage: TechCardStage | undefined;
  status: string | undefined;
  targetGender: GenderEnum | undefined;
  createdAt: wellKnownTimestamp | undefined;
  updatedAt: wellKnownTimestamp | undefined;
  approvalState: TechCardApprovalState | undefined;
  lockVersion: number | undefined;
  // Thumbnail URL for a grid/gallery view (idea gallery). For an IDEA card it is the first
  // moodboard image; otherwise the PREVIEW-kind sketch (falling back to the first technical, then any
  // media). Empty when the card has no media. Resolved server-side to avoid an N+1 GetTechCard.
  previewUrl: string | undefined;
  // Card purpose: "sellable" (default) or "auxiliary" (NF-07). Lets a board/list badge auxiliary
  // cards (dust bags, shoppers…) without an N+1 GetTechCard, mirroring TechCard.purpose.
  purpose: TechCardPurpose | undefined;
  skuSeason: SkuSeason | undefined;
  // WS7: auxiliary sub-type badge for list views (UNKNOWN=unset), mirroring purpose above.
  auxSubtype: TechCardAuxSubtype | undefined;
};

// MaterialMovementType is the kind of a material-stock movement (new-flow NF-01). quantity is
// always non-negative; the type (with on_hand before/after) encodes the direction.
export type MaterialMovementType =
  | "MATERIAL_MOVEMENT_TYPE_UNKNOWN"
  | "MATERIAL_MOVEMENT_TYPE_RECEIPT"
  | "MATERIAL_MOVEMENT_TYPE_RECEIPT_PRODUCTION"
  | "MATERIAL_MOVEMENT_TYPE_ISSUE_PRODUCTION"
  | "MATERIAL_MOVEMENT_TYPE_ISSUE_SAMPLE"
  | "MATERIAL_MOVEMENT_TYPE_RETURN_PRODUCTION"
  | "MATERIAL_MOVEMENT_TYPE_RETURN_SAMPLE"
  | "MATERIAL_MOVEMENT_TYPE_ADJUSTMENT"
  | "MATERIAL_MOVEMENT_TYPE_WRITEOFF";
// MaterialStock is a material's maintained on-hand balance and moving-average unit cost. The cost
// fields are confidential (stripped for accounts without costing:read).
export type MaterialStock = {
  materialId: number | undefined;
  onHand: googletype_Decimal | undefined;
  avgUnitCostBase: googletype_Decimal | undefined;
  baseCurrency: string | undefined;
  updatedAt: wellKnownTimestamp | undefined;
};

// MaterialMovement is one row of the append-only stock ledger. unit_cost* fields are confidential.
export type MaterialMovement = {
  id: number | undefined;
  materialId: number | undefined;
  movementType: MaterialMovementType | undefined;
  quantity: googletype_Decimal | undefined;
  onHandBefore: googletype_Decimal | undefined;
  onHandAfter: googletype_Decimal | undefined;
  unitCost: googletype_Decimal | undefined;
  currency: string | undefined;
  unitCostBase: googletype_Decimal | undefined;
  productionRunId: number | undefined;
  sampleId: number | undefined;
  techCardId: number | undefined;
  lot: string | undefined;
  supplierDoc: string | undefined;
  reason: string | undefined;
  comment: string | undefined;
  adminUsername: string | undefined;
  occurredAt: wellKnownTimestamp | undefined;
  createdAt: wellKnownTimestamp | undefined;
  productId: number | undefined;
  lotId: number | undefined;
};

// MaterialLot is a received batch (roll / dye-lot) of a material (gap-07 v2 D): a supplier lot code
// with a running remaining quantity, for traceability and colour matching. unit_cost is
// informational only — valuation stays moving-average; a lot is NOT a FIFO costing basis.
export type MaterialLot = {
  id: number | undefined;
  materialId: number | undefined;
  lotCode: string | undefined;
  supplierDoc: string | undefined;
  receivedQty: googletype_Decimal | undefined;
  remainingQty: googletype_Decimal | undefined;
  unitCost: googletype_Decimal | undefined;
  currency: string | undefined;
  receivedAt: wellKnownTimestamp | undefined;
  note: string | undefined;
  archived: boolean | undefined;
};

// MaterialStockRow is a catalog material joined with its stock balance, valuation and low-stock
// flag — one row of the warehouse list. Money fields are confidential.
export type MaterialStockRow = {
  material: Material | undefined;
  onHand: googletype_Decimal | undefined;
  avgUnitCostBase: googletype_Decimal | undefined;
  stockValueBase: googletype_Decimal | undefined;
  minStock: googletype_Decimal | undefined;
  belowMinStock: boolean | undefined;
  baseCurrency: string | undefined;
};

// BodyMeasurementName enumerates the body-measurement types captured for a fit
// model. It is intentionally separate from the garment MeasurementName dictionary.
export type BodyMeasurementName =
  | "BODY_MEASUREMENT_NAME_UNKNOWN"
  // Torso
  | "BODY_MEASUREMENT_NAME_CHEST"
  | "BODY_MEASUREMENT_NAME_UNDER_BUST"
  | "BODY_MEASUREMENT_NAME_WAIST"
  | "BODY_MEASUREMENT_NAME_HIGH_HIP"
  | "BODY_MEASUREMENT_NAME_HIP"
  | "BODY_MEASUREMENT_NAME_NECK_BASE"
  // Arms
  | "BODY_MEASUREMENT_NAME_ACROSS_SHOULDER"
  | "BODY_MEASUREMENT_NAME_SLEEVE_LENGTH"
  | "BODY_MEASUREMENT_NAME_BICEP"
  | "BODY_MEASUREMENT_NAME_WRIST"
  // Legs
  | "BODY_MEASUREMENT_NAME_INSEAM"
  | "BODY_MEASUREMENT_NAME_THIGH"
  | "BODY_MEASUREMENT_NAME_KNEE"
  | "BODY_MEASUREMENT_NAME_CALF"
  | "BODY_MEASUREMENT_NAME_ANKLE"
  // Vertical / lengths
  | "BODY_MEASUREMENT_NAME_HEIGHT"
  | "BODY_MEASUREMENT_NAME_HPS_TO_WAIST_FRONT"
  | "BODY_MEASUREMENT_NAME_CB_NECK_TO_WAIST"
  // Widths (front / back)
  | "BODY_MEASUREMENT_NAME_ACROSS_FRONT"
  | "BODY_MEASUREMENT_NAME_ACROSS_BACK";
// ModelMeasurement is a single body measurement value, in millimetres.
export type ModelMeasurement = {
  name: BodyMeasurementName | undefined;
  valueMm: number | undefined;
};

// ModelInsert is the writable payload for a fit-model profile. Measurements are
// sparse: include only the ones that are filled in.
export type ModelInsert = {
  name: string | undefined;
  comment: string | undefined;
  gender: GenderEnum | undefined;
  measurements: ModelMeasurement[] | undefined;
  thumbnailId: number | undefined;
  mediaIds: number[] | undefined;
  defaultSizeIds: number[] | undefined;
};

// Model is a stored fit-model profile.
export type Model = {
  id: number | undefined;
  model: ModelInsert | undefined;
  createdAt: wellKnownTimestamp | undefined;
  updatedAt: wellKnownTimestamp | undefined;
  thumbnail: MediaFull | undefined;
  media: MediaFull[] | undefined;
};

// ProductionRunStatus is the lifecycle state of a production run (партия). A run is planned, then
// started (in_progress), then received into stock, then closed; it can be cancelled from any
// non-terminal state. Stored as its lowercase name in the DB.
export type ProductionRunStatus =
  | "PRODUCTION_RUN_STATUS_UNKNOWN"
  | "PRODUCTION_RUN_STATUS_PLANNED"
  | "PRODUCTION_RUN_STATUS_IN_PROGRESS"
  | "PRODUCTION_RUN_STATUS_RECEIVED"
  | "PRODUCTION_RUN_STATUS_CLOSED"
  | "PRODUCTION_RUN_STATUS_CANCELLED";
// ProductionRunCostKind is the article category of an actual production-run cost.
export type ProductionRunCostKind =
  | "PRODUCTION_RUN_COST_KIND_UNKNOWN"
  | "PRODUCTION_RUN_COST_KIND_MATERIALS"
  | "PRODUCTION_RUN_COST_KIND_CMT"
  | "PRODUCTION_RUN_COST_KIND_HARDWARE"
  | "PRODUCTION_RUN_COST_KIND_PACKAGING"
  | "PRODUCTION_RUN_COST_KIND_LOGISTICS"
  | "PRODUCTION_RUN_COST_KIND_DUTY"
  | "PRODUCTION_RUN_COST_KIND_OTHER";
// ProductionMarkerSource is the CAD/nesting software (or hand entry) a marker record came from.
export type ProductionMarkerSource =
  | "PRODUCTION_MARKER_SOURCE_UNKNOWN"
  | "PRODUCTION_MARKER_SOURCE_GERBER"
  | "PRODUCTION_MARKER_SOURCE_OPTITEX"
  | "PRODUCTION_MARKER_SOURCE_LECTRA"
  | "PRODUCTION_MARKER_SOURCE_AUDACES"
  | "PRODUCTION_MARKER_SOURCE_MANUAL"
  | "PRODUCTION_MARKER_SOURCE_OTHER";
// ProductionRunLine is one colour-model × size line of a run: which product (colourway) at which
// size, the planned quantity, and — once received — the received and defective counts (unset until
// received) that drive plan/fact. product_id may be 0 while planning (the colourway may not be
// published as a product yet), but every line with a received_qty > 0 must carry it at receive
// time. Replaces the flat ProductionRunSize grid so one marker yields several colour-models (NF-06).
export type ProductionRunLine = {
  productId: number | undefined;
  sizeId: number | undefined;
  plannedQty: number | undefined;
  receivedQty?: number;
  defectQty?: number;
};

// ProductionRunCost is one actual cost article incurred for a run (phase 2). amount is in
// `currency`; amount_base is the base-currency equivalent — server-folded via the costing FX
// rates when left unset on write, or supplied manually — so run totals need no read-time FX.
export type ProductionRunCost = {
  kind: ProductionRunCostKind | undefined;
  description: string | undefined;
  amount: googletype_Decimal | undefined;
  currency: string | undefined;
  amountBase: googletype_Decimal | undefined;
  incurredAt: wellKnownTimestamp | undefined;
};

// ProductionRunCostByKind is the base-currency total of actual costs of one kind.
export type ProductionRunCostByKind = {
  kind: ProductionRunCostKind | undefined;
  amountBase: googletype_Decimal | undefined;
};

// ProductionRunActuals is the computed-on-read plan/fact summary of a run: actual totals from the
// cost articles + the phase-1 size grid, against the frozen planned unit cost.
export type ProductionRunActuals = {
  actualTotalBase: googletype_Decimal | undefined;
  baseCurrency: string | undefined;
  plannedQtyTotal: number | undefined;
  receivedQtyTotal: number | undefined;
  defectQtyTotal: number | undefined;
  actualUnitCost: googletype_Decimal | undefined;
  defectPctActual: googletype_Decimal | undefined;
  byKind: ProductionRunCostByKind[] | undefined;
  plannedTotalBase: googletype_Decimal | undefined;
  unitCostVariance: googletype_Decimal | undefined;
  totalVariance: googletype_Decimal | undefined;
  hasBase: boolean | undefined;
  // materials issued from the warehouse (NF-06): Σ (issue_production − return_production) ×
  // unit_cost_base. Folded INTO actual_total_base, so a run can cost its fabric either by hand
  // (a kind=materials cost article) or from stock issues — or, with the caveat below, both.
  materialsFromStockBase: googletype_Decimal | undefined;
  mixedMaterialsSources: boolean | undefined;
  hasUncostedIssues: boolean | undefined;
  // Per-colourway material cost (gap-07 v2 C): stock issues grouped by the product_id they were cut
  // for. Covers materials_from_stock only (manual cost articles stay run-level). Issues with no
  // product_id fall into unattributed_materials_base, not any colourway.
  byColorway: ProductionRunColorwayCost[] | undefined;
  unattributedMaterialsBase: googletype_Decimal | undefined;
};

// ProductionRunColorwayCost is one colour-model's slice of a run's material-from-stock cost (gap-07
// v2 C): the net material issued for that product and, if it received units, its per-unit material
// cost. Manual (non-stock) cost articles are run-level and are NOT split here.
export type ProductionRunColorwayCost = {
  productId: number | undefined;
  receivedQty: number | undefined;
  materialsFromStockBase: googletype_Decimal | undefined;
  materialsUnitCost: googletype_Decimal | undefined;
  hasUncosted: boolean | undefined;
};

// ProductionRunMarker is one imported nesting marker (раскладка / lay) of a run (gap-07 v2 E): the
// CAD source, the fabric width and lay length it was nested on, the units it yields, its
// fabric-utilisation %, an optional fabric/size, and a reference URL to the exported marker file.
// It is planning / traceability data — nothing here feeds the run's actual cost or cost_price.
export type ProductionRunMarker = {
  source: ProductionMarkerSource | undefined;
  markerName: string | undefined;
  sizeId: number | undefined;
  materialId: number | undefined;
  markerWidth: googletype_Decimal | undefined;
  layLength: googletype_Decimal | undefined;
  unitsPerMarker: number | undefined;
  efficiencyPct: googletype_Decimal | undefined;
  markerFileUrl: string | undefined;
  notes: string | undefined;
};

// ProductionRunInsert is the writable payload for a run (header + colour-model × size lines).
// planned_unit_cost / planned_currency are NOT here — they are server-snapshotted at plan time
// (from the linked tech_card_release or the live card's computed costing) and are read-only on write.
export type ProductionRunInsert = {
  techCardId: number | undefined;
  releaseId: number | undefined;
  status: ProductionRunStatus | undefined;
  startedAt: wellKnownTimestamp | undefined;
  receivedAt: wellKnownTimestamp | undefined;
  notes: string | undefined;
  lines: ProductionRunLine[] | undefined;
  costs: ProductionRunCost[] | undefined;
  markerEfficiencyPct: googletype_Decimal | undefined;
  markerNotes: string | undefined;
  markers: ProductionRunMarker[] | undefined;
  // Run ACTUAL cutting wastage % (0..100), entered per run once the marker/lay is known. When set it
  // OVERRIDES the BOM line's estimate wastage_percent in the run's cost calc (planned-cost snapshot +
  // material plan); unset falls back to the BOM estimate. Refines the plan side only — the run's ACTUAL
  // cost still derives from real material issues.
  actualWastagePercent: googletype_Decimal | undefined;
};

// ProductionRun is a stored run: the writable payload plus the server-owned identity, the frozen
// plan snapshot, and timestamps.
export type ProductionRun = {
  id: number | undefined;
  run: ProductionRunInsert | undefined;
  plannedUnitCost: googletype_Decimal | undefined;
  plannedCurrency: string | undefined;
  createdAt: wellKnownTimestamp | undefined;
  updatedAt: wellKnownTimestamp | undefined;
  actuals: ProductionRunActuals | undefined;
  // Optimistic-lock token, bumped on every UpdateProductionRun. Echo into
  // UpdateProductionRunRequest.expected_lock_version so a list→edit needs no extra GET (mirrors
  // TechCard.lock_version).
  lockVersion: number | undefined;
};

// SampleInsert is the writable payload of a sample (сэмпл) — a sewn prototype of a style
// (new-flow NF-04). number is server-assigned (MAX+1 per tech card) and not part of the payload.
export type SampleInsert = {
  techCardId: number | undefined;
  purpose: string | undefined;
  sizeId: number | undefined;
  colorwayId: number | undefined;
  status: string | undefined;
  fabricSource: string | undefined;
  notes: string | undefined;
  startedAt: string | undefined;
  finishedAt: string | undefined;
  mediaIds: number[] | undefined;
  patternUrl: string | undefined;
  patternNote: string | undefined;
  // Round spine (Q7/§2.7): a sample is the OBJECT of a development round.
  roundNumber: number | undefined;
  specReleaseId: number | undefined;
  previousSampleId: number | undefined;
};

// SampleSubstitutionInsert records a dev-time deviation from the spec BOM on a sample (§2.7): a BOM
// line was sewn with a different material. Q2 invariant: this is documentation, never COGS — the
// authoritative spend stays in the stock ledger (actual) and the BOM line (plan).
export type SampleSubstitutionInsert = {
  sampleId: number | undefined;
  bomItemId: number | undefined;
  originalMaterialId: number | undefined;
  substitutedMaterialId: number | undefined;
  reason: string | undefined;
  plannedQty: googletype_Decimal | undefined;
  actualQty: googletype_Decimal | undefined;
};

// SampleSubstitution is a stored substitution (insert payload + identity, audit stamp and timestamp).
export type SampleSubstitution = {
  id: number | undefined;
  sampleId: number | undefined;
  bomItemId: number | undefined;
  originalMaterialId: number | undefined;
  substitutedMaterialId: number | undefined;
  reason: string | undefined;
  plannedQty: googletype_Decimal | undefined;
  actualQty: googletype_Decimal | undefined;
  createdBy: string | undefined;
  createdAt: wellKnownTimestamp | undefined;
};

// SampleCost is the composed cost of a sample in the base currency (confidential; stripped without
// costing:read): materials issued from the warehouse plus the manual dev-expense journal.
export type SampleCost = {
  materialsBase: googletype_Decimal | undefined;
  manualBase: googletype_Decimal | undefined;
  totalBase: googletype_Decimal | undefined;
  hasUncosted: boolean | undefined;
};

// Sample is a stored sample: the writable payload plus identity, its per-card number, timestamps,
// and (on GetSample) the composed cost.
export type Sample = {
  id: number | undefined;
  sample: SampleInsert | undefined;
  number: number | undefined;
  createdAt: wellKnownTimestamp | undefined;
  updatedAt: wellKnownTimestamp | undefined;
  cost: SampleCost | undefined;
  media: MediaFull[] | undefined;
  lockVersion: number | undefined;
  createdBy: string | undefined;
  updatedBy: string | undefined;
};

// Subscriber represents the subscriber table
export type Subscriber = {
  id: number | undefined;
  name: string | undefined;
  email: string | undefined;
  receivePromoEmails: boolean | undefined;
};

export type SupportTicketStatus =
  | "SUPPORT_TICKET_STATUS_UNKNOWN"
  | "SUPPORT_TICKET_STATUS_SUBMITTED"
  | "SUPPORT_TICKET_STATUS_IN_PROGRESS"
  | "SUPPORT_TICKET_STATUS_WAITING_CUSTOMER"
  | "SUPPORT_TICKET_STATUS_RESOLVED"
  | "SUPPORT_TICKET_STATUS_CLOSED";
export type SupportTicketPriority =
  | "SUPPORT_TICKET_PRIORITY_UNKNOWN"
  | "SUPPORT_TICKET_PRIORITY_LOW"
  | "SUPPORT_TICKET_PRIORITY_MEDIUM"
  | "SUPPORT_TICKET_PRIORITY_HIGH"
  | "SUPPORT_TICKET_PRIORITY_URGENT";
export type SupportTicketInsert = {
  topic: string | undefined;
  subject: string | undefined;
  civility: string | undefined;
  email: string | undefined;
  firstName: string | undefined;
  lastName: string | undefined;
  orderReference: string | undefined;
  notes: string | undefined;
  category: string | undefined;
  priority: SupportTicketPriority | undefined;
};

export type SupportTicket = {
  id: number | undefined;
  createdAt: wellKnownTimestamp | undefined;
  updatedAt: wellKnownTimestamp | undefined;
  status: SupportTicketStatus | undefined;
  resolvedAt: wellKnownTimestamp | undefined;
  supportTicketInsert: SupportTicketInsert | undefined;
  caseNumber: string | undefined;
  category: string | undefined;
  priority: SupportTicketPriority | undefined;
  internalNotes: string | undefined;
};

// TaskBoard is the department lane a task lives in. Fixed taxonomy for now; a
// task belongs to exactly one board. Extend by appending members (never reuse
// numbers) — 0 stays UNKNOWN per proto3 convention.
export type TaskBoard =
  | "TASK_BOARD_UNKNOWN"
  | "TASK_BOARD_DEVELOPMENT"
  | "TASK_BOARD_DESIGN"
  | "TASK_BOARD_MARKETING"
  | "TASK_BOARD_PRODUCTION"
  | "TASK_BOARD_SOURCING"
  | "TASK_BOARD_CONTENT";
// TaskStatus is the kanban column. A drag between columns is a status change.
export type TaskStatus =
  | "TASK_STATUS_UNKNOWN"
  | "TASK_STATUS_BACKLOG"
  | "TASK_STATUS_TODO"
  | "TASK_STATUS_IN_PROGRESS"
  | "TASK_STATUS_REVIEW"
  | "TASK_STATUS_DONE";
export type TaskPriority =
  | "TASK_PRIORITY_UNKNOWN"
  | "TASK_PRIORITY_LOW"
  | "TASK_PRIORITY_MEDIUM"
  | "TASK_PRIORITY_HIGH"
  | "TASK_PRIORITY_URGENT";
// TaskInsert is the writable CONTENT of a task (create/update). Placement on the
// board — board, status, position — is deliberately NOT here: it is set at
// AddTask and changed only via MoveTask, so a content edit can never silently
// re-file a card into another lane/column or reorder it. Other server-managed
// fields (id, created_by, timestamps, resolved media) also live on Task.
export type TaskInsert = {
  title: string | undefined;
  description: string | undefined;
  assignee: string | undefined;
  priority: TaskPriority | undefined;
  dueDate: wellKnownTimestamp | undefined;
  labels: string[] | undefined;
  mediaIds: number[] | undefined;
  // Optional typed links to existing admin entities (0 / "" = none). Follows the
  // fitting precedent (several nullable typed FKs, NOT a polymorphic entity_type
  // ref) so a card can deep-link to the artifact it is about while that artifact
  // keeps its own state machine (techcard stage/approval, fitting verdict, …).
  // Each target has a single-get RPC so the card can resolve a title/thumbnail.
  techCardId: number | undefined;
  productId: number | undefined;
  orderUuid: string | undefined;
  archiveId: number | undefined;
  fittingId: number | undefined;
  productionRunId: number | undefined;
  sampleId: number | undefined;
  // Planned start (when work SHOULD begin), the manual counterpart of due_date.
  // The ACTUAL start (when the card first entered IN_PROGRESS) is the
  // server-stamped Task.started_at, not this field. Unset = no planned start.
  startDate: wellKnownTimestamp | undefined;
};

// TaskChecklistItem is one row of a task's checklist — a lightweight subtask with
// a done flag. Checklist items are managed by dedicated add/toggle/delete RPCs
// (NOT bundled into TaskInsert's replace-on-update semantics like labels/media),
// so a content edit never wipes per-item done state.
export type TaskChecklistItem = {
  id: number | undefined;
  taskId: number | undefined;
  content: string | undefined;
  isDone: boolean | undefined;
  position: number | undefined;
  createdAt: wellKnownTimestamp | undefined;
};

// Task is a stored kanban card: its content (TaskInsert), its placement on the
// board (board/status/position — server-managed, set by AddTask and mutated only
// by MoveTask), resolved media, and server-stamped identity/timestamps.
export type Task = {
  id: number | undefined;
  task: TaskInsert | undefined;
  board: TaskBoard | undefined;
  status: TaskStatus | undefined;
  position: number | undefined;
  media: MediaFull[] | undefined;
  createdBy: string | undefined;
  createdAt: wellKnownTimestamp | undefined;
  updatedAt: wellKnownTimestamp | undefined;
  // Soft-archive: set = the card is archived (hidden from the board and default
  // list, but preserved and restorable via UnarchiveTask); unset = active.
  // Orthogonal to placement — archiving does not change board/status/position.
  archivedAt: wellKnownTimestamp | undefined;
  checklist: TaskChecklistItem[] | undefined;
  // Actual start: server-stamped the FIRST time the card enters IN_PROGRESS
  // (never client-supplied, never cleared on later moves). Unset = the card has
  // not been started yet. This is distinct from the planned TaskInsert.start_date.
  startedAt: wellKnownTimestamp | undefined;
};

// TaskCommentInsert is the writable payload for a comment. author is set
// server-side from the caller's JWT (not client-supplied).
export type TaskCommentInsert = {
  taskId: number | undefined;
  body: string | undefined;
};

export type TaskComment = {
  id: number | undefined;
  taskId: number | undefined;
  author: string | undefined;
  body: string | undefined;
  createdAt: wellKnownTimestamp | undefined;
};


